Here's a shorter reproducer. For 64-bits machine (movq and rsp, instead of movl and esp). Compile with `gcc -shared -o mylib.so mylib.c`. Run in julia with e.g. `@ccall "./mylib.so".checkstack()::Nothing`.

```
#include <stdint.h>
#include <stdio.h>
#include <pthread.h>

int pthread_getattr_np(pthread_t thread, pthread_attr_t *attr);

intptr_t currentStackPtr() {
  intptr_t value;
  asm ("movq %%rsp, %0;" : "=a" (value));
  return value;
}

void checkstack() {
  pthread_t self = pthread_self();
  pthread_attr_t threadAttr;
  intptr_t base;
  size_t size;
  int stat = pthread_getattr_np(self, &threadAttr);
  stat = pthread_attr_getstack(&threadAttr, (void **) &base, &size);
  intptr_t mysp = currentStackPtr();

  printf("base=%p, base+size=%p, mysp=%p success=%d\n", 
	 (void*)base, (void*)(base+size), (void*) mysp,
	 base <= mysp && mysp <= base+size);
}

static void init() __attribute__((constructor));
static void init() {
  checkstack();
}
